settings.custom_css:
.elementor-widget-text-editor p{margin:0}
@keyframes ub-spin{to{transform:rotate(360deg)}}
@keyframes ub-float2{0%,100%{transform:translateY(0) rotate(0deg)}50%{transform:translateY(-14px) rotate(4deg)}}
@keyframes ub-marquee{from{transform:translateX(0)}to{transform:translateX(-50%)}}
@keyframes ub-drift{from{transform:translateX(6%)}to{transform:translateX(-24%)}}
.ub-rv{opacity:0;transform:translateY(32px);transition:opacity .85s cubic-bezier(.16,1,.3,1),transform .85s cubic-bezier(.16,1,.3,1);will-change:opacity,transform}
.ub-rv.ub-in{opacity:1 !important;transform:none !important}
.ub-outline .elementor-heading-title{color:transparent;-webkit-text-stroke:1.5px #FFC107}
.ub-outline2 .elementor-heading-title{color:transparent;-webkit-text-stroke:2px #FFC107}
.ub-outline-w .elementor-heading-title{color:transparent;-webkit-text-stroke:1.5px rgba(255,255,255,.14);white-space:nowrap}
.ub-tex-hero{background-color:#0e0e0e;background-image:repeating-linear-gradient(120deg,rgba(255,255,255,.028) 0 14px,transparent 14px 30px)}
.ub-tex-plate{background-color:#141414;background-image:repeating-linear-gradient(135deg,rgba(255,255,255,.03) 0 12px,transparent 12px 24px)}
.ub-plabel{font-family:ui-monospace,Menlo,monospace !important;border:1px dashed rgba(255,255,255,.22);padding:8px 14px;display:inline-block}
.ub-plabel .elementor-heading-title{font-family:ui-monospace,Menlo,monospace}
#ub-nav{position:fixed;top:0;left:0;width:100%;z-index:100;background:transparent;border-bottom:1px solid transparent;transition:background .35s,border-color .35s,box-shadow .35s}
#ub-nav.ub-scrolled{background:#000;border-bottom:1px solid #1a1a1a;box-shadow:0 8px 30px rgba(0,0,0,.5)}
#ub-progress{position:fixed;top:0;left:0;height:3px;width:0;padding:0;min-height:0;background:#FFC107;z-index:120;transition:width .1s linear}
.ub-btn-gold .elementor-button{transition:transform .25s,box-shadow .25s}
.ub-btn-gold .elementor-button:hover{transform:translateY(-3px);box-shadow:0 14px 34px rgba(255,193,7,.4);background:#FFC107;color:#000}
.ub-btn-outline .elementor-button{transition:background .25s,border-color .25s}
.ub-btn-outline .elementor-button:hover{background:rgba(255,255,255,.08) !important;border-color:#fff !important}
#ub-burger{display:none;flex-direction:column;gap:5px;cursor:pointer}
#ub-burger .ub-bar{width:26px;height:2px;background:#fff}
#ub-burger .ub-bar.g{width:18px;background:#FFC107}
#ub-mobile-menu{position:fixed;inset:0;z-index:110;background:#000;display:flex;flex-direction:column;padding:26px 30px;opacity:0;visibility:hidden;transform:translateY(-100%);pointer-events:none;transition:transform .45s cubic-bezier(.16,1,.3,1),opacity .35s ease,visibility 0s linear .45s}
#ub-mobile-menu.ub-open{opacity:1;visibility:visible;transform:none;pointer-events:auto;transition:transform .45s cubic-bezier(.16,1,.3,1),opacity .35s ease}
.ub-mlink .elementor-heading-title{font-family:Anton;font-size:46px;color:#fff;text-transform:uppercase;letter-spacing:.01em;line-height:1.1}
.ub-mclose{cursor:pointer}
.ub-about-grid{display:grid !important;grid-template-columns:1.05fr .95fr;gap:clamp(40px,6vw,90px);align-items:center}
.ub-feat-grid{display:grid !important;grid-template-columns:1fr 1fr;gap:14px 30px}
.ub-why-grid{display:grid !important;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:1px;background:#1a1a1a;border:1px solid #1a1a1a}
.ub-prog-grid{display:grid !important;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:22px}
.ub-price-grid{display:grid !important;grid-template-columns:repeat(4,1fr);gap:18px;align-items:stretch}
.ub-foot-grid{display:grid !important;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:44px 32px}
.ub-whycell{transition:background .3s}
.ub-whycell:hover{background:#111 !important}
.ub-progcard{transition:transform .35s,border-color .35s}
.ub-progcard:hover{transform:translateY(-6px);border-color:#333 !important}
.ub-social{transition:border-color .2s}
.ub-social .elementor-heading-title{transition:color .2s}
.ub-social:hover{border-color:#FFC107 !important}
.ub-social:hover .elementor-heading-title{color:#FFC107 !important}
.ub-flink .elementor-heading-title{transition:color .2s}
.ub-flink:hover .elementor-heading-title{color:#fff !important}
.ub-spin{animation:ub-spin 34s linear infinite}
.ub-spin-slow{animation:ub-spin 60s linear infinite}
.ub-float{animation:ub-float2 7s ease-in-out infinite}
.ub-drift .elementor-heading-title{animation:ub-drift 26s linear infinite alternate;white-space:nowrap;display:inline-block}
.ub-marq-mask{-webkit-mask-image:linear-gradient(90deg,transparent,#000 8%,#000 92%,transparent);mask-image:linear-gradient(90deg,transparent,#000 8%,#000 92%,transparent)}
.ub-marq-track{display:inline-flex;gap:64px;animation:ub-marquee 32s linear infinite;will-change:transform;white-space:nowrap}
.ub-scrollcue{position:absolute;bottom:26px;left:50%;transform:translateX(-50%)}
@media(max-width:900px){
 #ub-nav-desk{display:none !important}
 #ub-nav-cta{display:none !important}
 #ub-burger{display:flex !important}
 .ub-hero-pad{padding-left:24px !important;padding-right:24px !important}
 .ub-about-grid{grid-template-columns:1fr !important}
 .ub-hero-inner{flex-direction:column !important;align-items:flex-start !important}
}
@media(max-width:600px){.ub-price-grid{grid-template-columns:1fr !important}}
.ub-d0{transition-delay:0.00s}.ub-d60{transition-delay:0.06s}.ub-d70{transition-delay:0.07s}.ub-d80{transition-delay:0.08s}.ub-d140{transition-delay:0.14s}.ub-d160{transition-delay:0.16s}.ub-d180{transition-delay:0.18s}.ub-d220{transition-delay:0.22s}.ub-d240{transition-delay:0.24s}.ub-d260{transition-delay:0.26s}.ub-d300{transition-delay:0.30s}.ub-d320{transition-delay:0.32s}.ub-d400{transition-delay:0.40s}.ub-d480{transition-delay:0.48s}
.ub-plabel-lg{padding:9px 16px}
.ub-plabel-sm{padding:7px 12px;border-color:rgba(255,255,255,.2)}
.ub-plabel-dim{border-color:rgba(255,255,255,.16)}
.ub-float-b{animation:ub-float2 8s ease-in-out infinite .6s}
.ub-float-c{animation:ub-float2 7.5s ease-in-out infinite .3s}
.ub-hv-nav .elementor-button:hover{transform:translateY(-2px);box-shadow:0 10px 26px rgba(255,193,7,.4)}
.ub-hv-sm .elementor-button:hover{transform:translateY(-2px);box-shadow:0 12px 30px rgba(255,193,7,.4)}
.ub-hv-lg .elementor-button:hover{transform:translateY(-3px);box-shadow:0 16px 40px rgba(255,193,7,.4)}
#ub-mclose{width:44px;height:44px;border:1px solid #2A2A2A;border-radius:2px;display:flex;align-items:center;justify-content:center}

/* --- nav row: never wrap; keep burger beside logo on mobile --- */
.ub-nav-row{flex-wrap:nowrap !important}
/* burger row: no wrap, burger hugs content */
.ub-nav-row > .e-con-inner{flex-wrap:nowrap !important}
#ub-burger{width:auto !important;flex:0 0 auto !important}

#ub-nav .elementor-widget-image img{max-width:min(210px,52vw);height:auto}
#ub-burger{flex-shrink:0}
/* --- footer social icons --- */
.ub-social-fa .elementor-social-icon{border:1px solid #262626;border-radius:2px;transition:border-color .2s,transform .2s}
.ub-social-fa .elementor-social-icon:hover{border-color:#FFC107;transform:translateY(-2px)}
.ub-social-fa .elementor-social-icon:hover i{color:#FFC107}
/* --- Gravity Forms dark theme --- */
.ub-gf .gform_wrapper{font-family:Inter,sans-serif}
.ub-gf .gform_wrapper .gfield_label{color:rgba(255,255,255,.85);font-family:Inter,sans-serif;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.08em}
.ub-gf .gform_wrapper .gfield_required{color:#FFC107 !important}
.ub-gf .gform_wrapper input:not([type=submit]):not([type=button]):not([type=radio]):not([type=checkbox]),.ub-gf .gform_wrapper select,.ub-gf .gform_wrapper textarea{background:#0a0a0a !important;border:1px solid #262626 !important;color:#fff !important;border-radius:2px;padding:12px 14px !important;font-family:Inter,sans-serif !important;font-size:14px !important;width:100%}
.ub-gf .gform_wrapper input:focus,.ub-gf .gform_wrapper select:focus,.ub-gf .gform_wrapper textarea:focus{border-color:#FFC107 !important;outline:none !important;box-shadow:none !important}
.ub-gf .gform_wrapper ::placeholder{color:rgba(255,255,255,.35)}
.ub-gf .gform_wrapper select option{background:#0a0a0a;color:#fff}
.ub-gf .gform_wrapper textarea{min-height:130px}
.ub-gf .gform_wrapper .gform_button{background:#FFC107 !important;color:#000 !important;border:0 !important;border-radius:2px;font-family:Inter,sans-serif !important;font-weight:800;font-size:14px;text-transform:uppercase;letter-spacing:.04em;padding:18px 30px !important;cursor:pointer;width:100%;transition:transform .25s,box-shadow .25s}
.ub-gf .gform_wrapper .gform_button:hover{transform:translateY(-2px);box-shadow:0 14px 34px rgba(255,193,7,.4)}
.ub-gf .gform_wrapper .gform_footer{margin-top:6px;padding:0}
.ub-gf .gform_wrapper .gfield_validation_message,.ub-gf .gform_wrapper .validation_message{background:transparent;border:0;color:#ff8a80;font-size:12.5px;padding:4px 0 0}
.ub-gf .gform_wrapper .gform_validation_errors{background:#1a0d0d;border:1px solid #5c2222;border-radius:2px;box-shadow:none}
.ub-gf .gform_wrapper .gform_validation_errors *{color:#ff8a80}
.ub-gf .gform_confirmation_message{color:rgba(255,255,255,.85);font-family:Inter,sans-serif;font-size:15px;line-height:1.6;border:1px solid #FFC107;border-radius:2px;padding:18px 20px;display:block}
.ub-gf .gform_wrapper .gfield{margin-bottom:14px}
/* newsletter inline variant */
.ub-gf-news .gform_wrapper form{display:flex;gap:10px;align-items:flex-start}
.ub-gf-news .gform_wrapper .gform_body{flex:1}
.ub-gf-news .gform_wrapper .gfield{margin-bottom:0}
.ub-gf-news .gform_wrapper .gform_footer{margin-top:0;width:auto}
.ub-gf-news .gform_wrapper .gform_button{width:auto;padding:13px 18px !important;font-size:12.5px}
.ub-gf-news .gform_wrapper input[type=email]{padding:12px 12px !important}

/* --- editor-only: reveal-on-scroll content so it is visible & editable in the Elementor editor (front-end animations unaffected; .elementor-editor-active exists only in the editor) --- */
.elementor-editor-active .ub-rv{opacity:1 !important;transform:none !important;transition:none !important}
.elementor-editor-active .ub-drift .elementor-heading-title,.elementor-editor-active .ub-marq-track{animation:none !important}
